    /**
     * Hash a password using WordPress's built-in password hashing (bcrypt/phpass)
     */
    public function hash_password($password) {
        if (!function_exists('wp_hash_password')) {
            require_once(ABSPATH . WPINC . '/pluggable.php');
        }
        return wp_hash_password($password);
    }

    /**
     * Verify a password against a stored hash
     */
    public function verify_password($password, $hash) {
        if (!function_exists('wp_check_password')) {
            require_once(ABSPATH . WPINC . '/pluggable.php');
        }
        return wp_check_password($password, $hash);
    }

    /**
     * Validate password strength
     */
    public function validate_password($password) {
        $errors = array();
        $min_length = get_option('custom_auth_min_password_length', 8);
        $require_special = get_option('custom_auth_require_special_chars', 1);
        $require_uppercase = get_option('custom_auth_require_uppercase', 1);
        $require_numbers = get_option('custom_auth_require_numbers', 1);

        if (strlen($password) < $min_length) {
            $errors[] = sprintf('Password must be at least %d characters long.', $min_length);
        }

        if ($require_uppercase && !preg_match('/[A-Z]/', $password)) {
            $errors[] = 'Password must contain at least one uppercase letter.';
        }

        if ($require_numbers && !preg_match('/[0-9]/', $password)) {
            $errors[] = 'Password must contain at least one number.';
        }

        if ($require_special && !preg_match('/[^A-Za-z0-9]/', $password)) {
            $errors[] = 'Password must contain at least one special character.';
        }

        return $errors;
    }

    /**
     * Check if account is locked due to too many login attempts
     */
    private function is_account_locked($user) {
        $max_attempts = get_option('custom_auth_max_login_attempts', 5);
        $lockout_duration = get_option('custom_auth_lockout_duration', 30);

        if ($user->login_attempts >= $max_attempts && $user->last_login_attempt) {
            $lockout_time = strtotime($user->last_login_attempt) + ($lockout_duration * 60);
            if (time() < $lockout_time) {
                $remaining = ceil(($lockout_time - time()) / 60);
                return $remaining;
            } else {
                // Reset attempts after lockout period
                $this->reset_login_attempts($user->id);
                return false;
            }
        }
        return false;
    }

    /**
     * Increment login attempts
     */
    private function increment_login_attempts($user_id) {
        global $wpdb;
        $wpdb->query($wpdb->prepare(
            "UPDATE {$this->table_name} SET login_attempts = login_attempts + 1, last_login_attempt = NOW() WHERE id = %d",
            $user_id
        ));
    }

    /**
     * Reset login attempts
     */
    private function reset_login_attempts($user_id) {
        global $wpdb;
        $wpdb->update(
            $this->table_name,
            array('login_attempts' => 0, 'last_login_attempt' => null),
            array('id' => $user_id),
            array('%d', '%s'),
            array('%d')
        );
    }

    /**
     * Handle user registration via AJAX
     */
    public function handle_registration() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        $username = sanitize_user(isset($_POST['username']) ? $_POST['username'] : '');
        $email = sanitize_email(isset($_POST['email']) ? $_POST['email'] : '');
        $password = isset($_POST['password']) ? $_POST['password'] : '';
        $confirm_password = isset($_POST['confirm_password']) ? $_POST['confirm_password'] : '';
        $first_name = sanitize_text_field(isset($_POST['first_name']) ? $_POST['first_name'] : '');
        $last_name = sanitize_text_field(isset($_POST['last_name']) ? $_POST['last_name'] : '');

        // Validation
        if (empty($username) || empty($email) || empty($password)) {
            wp_send_json_error(array('message' => 'Username, email, and password are required.'));
            return;
        }

        if (strlen($username) < 3) {
            wp_send_json_error(array('message' => 'Username must be at least 3 characters long.'));
            return;
        }

        if (!preg_match('/^[a-zA-Z0-9_]+$/', $username)) {
            wp_send_json_error(array('message' => 'Username can only contain letters, numbers, and underscores.'));
            return;
        }

        if (!is_email($email)) {
            wp_send_json_error(array('message' => 'Please enter a valid email address.'));
            return;
        }

        if ($password !== $confirm_password) {
            wp_send_json_error(array('message' => 'Passwords do not match.'));
            return;
        }

        // Validate password strength
        $password_errors = $this->validate_password($password);
        if (!empty($password_errors)) {
            wp_send_json_error(array('message' => implode(' ', $password_errors)));
            return;
        }

        global $wpdb;

        // Check if username exists
        $existing_user = $wpdb->get_row($wpdb->prepare(
            "SELECT id FROM {$this->table_name} WHERE username = %s",
            $username
        ));

        if ($existing_user) {
            wp_send_json_error(array('message' => 'Username already exists.'));
            return;
        }

        // Check if email exists
        $existing_email = $wpdb->get_row($wpdb->prepare(
            "SELECT id FROM {$this->table_name} WHERE email = %s",
            $email
        ));

        if ($existing_email) {
            wp_send_json_error(array('message' => 'Email address already registered.'));
            return;
        }

        // Hash the password
        $password_hash = $this->hash_password($password);

        // Generate activation key
        $activation_key = wp_generate_password(32, false);

        // Insert user
        $result = $wpdb->insert(
            $this->table_name,
            array(
                'username' => $username,
                'email' => $email,
                'password_hash' => $password_hash,
                'first_name' => $first_name,
                'last_name' => $last_name,
                'is_active' => 1,
                'activation_key' => $activation_key,
                'created_at' => current_time('mysql'),
            ),
            array('%s', '%s', '%s', '%s', '%s', '%d', '%s', '%s')
        );

        if ($result === false) {
            wp_send_json_error(array('message' => 'Registration failed. Please try again.'));
            return;
        }

        $user_id = $wpdb->insert_id;

        // Also create a WordPress user for compatibility
        if (!username_exists($username) && !email_exists($email)) {
            $wp_user_id = wp_create_user($username, $password, $email);
            if (!is_wp_error($wp_user_id)) {
                wp_update_user(array(
                    'ID' => $wp_user_id,
                    'first_name' => $first_name,
                    'last_name' => $last_name,
                ));
            }
        }

        do_action('custom_auth_user_registered', $user_id, $username, $email);

        wp_send_json_success(array(
            'message' => 'Registration successful! You can now log in.',
            'user_id' => $user_id,
        ));
    }

    /**
     * Handle user login via AJAX
     */
    public function handle_login() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        $username = sanitize_user(isset($_POST['username']) ? $_POST['username'] : '');
        $password = isset($_POST['password']) ? $_POST['password'] : '';
        $remember_me = isset($_POST['remember_me']) ? (bool)$_POST['remember_me'] : false;

        if (empty($username) || empty($password)) {
            wp_send_json_error(array('message' => 'Username and password are required.'));
            return;
        }

        global $wpdb;

        // Find user by username or email
        $user = $wpdb->get_row($wpdb->prepare(
            "SELECT * FROM {$this->table_name} WHERE username = %s OR email = %s",
            $username,
            $username
        ));

        if (!$user) {
            wp_send_json_error(array('message' => 'Invalid username or password.'));
            return;
        }

        // Check if account is active
        if (!$user->is_active) {
            wp_send_json_error(array('message' => 'Your account has been deactivated. Please contact support.'));
            return;
        }

        // Check if account is locked
        $locked_minutes = $this->is_account_locked($user);
        if ($locked_minutes !== false) {
            wp_send_json_error(array(
                'message' => sprintf('Account is locked due to too many failed login attempts. Please try again in %d minutes.', $locked_minutes)
            ));
            return;
        }

        // Verify password
        if (!$this->verify_password($password, $user->password_hash)) {
            $this->increment_login_attempts($user->id);

            $max_attempts = get_option('custom_auth_max_login_attempts', 5);
            $remaining = $max_attempts - ($user->login_attempts + 1);

            if ($remaining <= 0) {
                wp_send_json_error(array(
                    'message' => 'Account has been locked due to too many failed login attempts.'
                ));
            } else {
                wp_send_json_error(array(
                    'message' => sprintf('Invalid username or password. %d attempts remaining.', max(0, $remaining))
                ));
            }
            return;
        }

        // Reset login attempts on successful login
        $this->reset_login_attempts($user->id);

        // Update last login
        $wpdb->update(
            $this->table_name,
            array('last_login' => current_time('mysql')),
            array('id' => $user->id),
            array('%s'),
            array('%d')
        );

        // Set session
        if (!session_id() && !headers_sent()) {
            session_start();
        }
        $_SESSION['custom_auth_user_id'] = $user->id;
        $_SESSION['custom_auth_username'] = $user->username;
        $_SESSION['custom_auth_logged_in'] = true;

        // Also log in to WordPress if user exists
        $wp_user = get_user_by('login', $user->username);
        if ($wp_user) {
            wp_set_current_user($wp_user->ID);
            wp_set_auth_cookie($wp_user->ID, $remember_me);
        }

        do_action('custom_auth_user_logged_in', $user->id, $user->username);

        wp_send_json_success(array(
            'message' => 'Login successful! Redirecting...',
            'redirect' => home_url(),
            'user' => array(
                'id' => $user->id,
                'username' => $user->username,
                'email' => $user->email,
                'first_name' => $user->first_name,
                'last_name' => $user->last_name,
            )
        ));
    }

    /**
     * Handle user logout
     */
    public function handle_logout() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        if (session_id()) {
            unset($_SESSION['custom_auth_user_id']);
            unset($_SESSION['custom_auth_username']);
            unset($_SESSION['custom_auth_logged_in']);
            session_destroy();
        }

        wp_logout();

        wp_send_json_success(array(
            'message' => 'Logged out successfully.',
            'redirect' => home_url(),
        ));
    }

    /**
     * Handle password change
     */
    public function handle_change_password() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        $current_user = $this->get_current_custom_user();
        if (!$current_user) {
            wp_send_json_error(array('message' => 'You must be logged in to change your password.'));
            return;
        }

        $current_password = isset($_POST['current_password']) ? $_POST['current_password'] : '';
        $new_password = isset($_POST['new_password']) ? $_POST['new_password'] : '';
        $confirm_new_password = isset($_POST['confirm_new_password']) ? $_POST['confirm_new_password'] : '';

        if (empty($current_password) || empty($new_password) || empty($confirm_new_password)) {
            wp_send_json_error(array('message' => 'All fields are required.'));
            return;
        }

        // Verify current password
        if (!$this->verify_password($current_password, $current_user->password_hash)) {
            wp_send_json_error(array('message' => 'Current password is incorrect.'));
            return;
        }

        if ($new_password !== $confirm_new_password) {
            wp_send_json_error(array('message' => 'New passwords do not match.'));
            return;
        }

        // Validate new password strength
        $password_errors = $this->validate_password($new_password);
        if (!empty($password_errors)) {
            wp_send_json_error(array('message' => implode(' ', $password_errors)));
            return;
        }

        // Make sure new password is different from current
        if ($this->verify_password($new_password, $current_user->password_hash)) {
            wp_send_json_error(array('message' => 'New password must be different from your current password.'));
            return;
        }

        // Hash and update the password
        $new_hash = $this->hash_password($new_password);

        global $wpdb;
        $result = $wpdb->update(
            $this->table_name,
            array('password_hash' => $new_hash),
            array('id' => $current_user->id),
            array('%s'),
            array('%d')
        );

        if ($result === false) {
            wp_send_json_error(array('message' => 'Failed to update password. Please try again.'));
            return;
        }

        // Also update WordPress user password
        $wp_user = get_user_by('login', $current_user->username);
        if ($wp_user) {
            wp_set_password($new_password, $wp_user->ID);
            // Re-authenticate after password change
            wp_set_current_user($wp_user->ID);
            wp_set_auth_cookie($wp_user->ID);
        }

        do_action('custom_auth_password_changed', $current_user->id);

        wp_send_json_success(array('message' => 'Password changed successfully.'));
    }

    /**
     * Get the currently logged in custom user
     */
    public function get_current_custom_user() {
        if (!session_id() && !headers_sent()) {
            session_start();
        }

        if (!isset($_SESSION['custom_auth_user_id']) || !$_SESSION['custom_auth_logged_in']) {
            return null;
        }

        global $wpdb;
        return $wpdb->get_row($wpdb->prepare(
            "SELECT * FROM {$this->table_name} WHERE id = %d AND is_active = 1",
            intval($_SESSION['custom_auth_user_id'])
        ));
    }

    /**
     * Check if a custom user is logged in
     */
    public function is_custom_user_logged_in() {
        return $this->get_current_custom_user() !== null;
    }

    /**
     * WordPress authenticate filter - also check our custom table
     */
    public function custom_authenticate($user, $username, $password) {
        if (is_a($user, 'WP_User')) {
            return $user;
        }

        if (empty($username) || empty($password)) {
            return $user;
        }

        global $wpdb;
        $custom_user = $wpdb->get_row($wpdb->prepare(
            "SELECT * FROM {$this->table_name} WHERE (username = %s OR email = %s) AND is_active = 1",
            $username,
            $username
        ));

        if ($custom_user && $this->verify_password($password, $custom_user->password_hash)) {
            // Try to find corresponding WP user
            $wp_user = get_user_by('login', $custom_user->username);
            if ($wp_user) {
                return $wp_user;
            }
        }

        return $user;
    }

