    /**
     * Admin users page
     */
    public function admin_users_page() {
        if (!current_user_can('manage_options')) {
            return;
        }

        global $wpdb;

        // Handle user actions
        if (isset($_GET['action']) && isset($_GET['user_id']) && check_admin_referer('custom_auth_user_action')) {
            $user_id = intval($_GET['user_id']);
            $action = sanitize_text_field($_GET['action']);

            switch ($action) {
                case 'activate':
                    $wpdb->update($this->table_name, array('is_active' => 1), array('id' => $user_id));
                    echo '<div class="notice notice-success"><p>User activated successfully.</p></div>';
                    break;
                case 'deactivate':
                    $wpdb->update($this->table_name, array('is_active' => 0), array('id' => $user_id));
                    echo '<div class="notice notice-success"><p>User deactivated successfully.</p></div>';
                    break;
                case 'reset_attempts':
                    $this->reset_login_attempts($user_id);
                    echo '<div class="notice notice-success"><p>Login attempts reset successfully.</p></div>';
                    break;
                case 'delete':
                    $wpdb->delete($this->table_name, array('id' => $user_id));
                    echo '<div class="notice notice-success"><p>User deleted successfully.</p></div>';
                    break;
            }
        }

        $users = $wpdb->get_results("SELECT * FROM {$this->table_name} ORDER BY created_at DESC");
        ?>
        <div class="wrap">
            <h1>Custom Auth Users</h1>

            <table class="wp-list-table widefat fixed striped">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Username</th>
                        <th>Email</th>
                        <th>Name</th>
                        <th>Status</th>
                        <th>Login Attempts</th>
                        <th>Last Login</th>
                        <th>Registered</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    <?php if (empty($users)): ?>
                    <tr>
                        <td colspan="9">No users found.</td>
                    </tr>
                    <?php else: ?>
                    <?php foreach ($users as $user): ?>
                    <tr>
                        <td><?php echo esc_html($user->id); ?></td>
                        <td><strong><?php echo esc_html($user->username); ?></strong></td>
                        <td><?php echo esc_html($user->email); ?></td>
                        <td><?php echo esc_html(trim($user->first_name . ' ' . $user->last_name)); ?></td>
                        <td>
                            <?php if ($user->is_active): ?>
                                <span style="color:green;">Active</span>
                            <?php else: ?>
                                <span style="color:red;">Inactive</span>
                            <?php endif; ?>
                        </td>
                        <td>
                            <?php echo esc_html($user->login_attempts); ?>
                            <?php if ($user->login_attempts > 0): ?>
                                <br><a href="<?php echo wp_nonce_url(admin_url('admin.php?page=custom-auth-users&action=reset_attempts&user_id=' . $user->id), 'custom_auth_user_action'); ?>">Reset</a>
                            <?php endif; ?>
                        </td>
                        <td><?php echo $user->last_login ? esc_html(date('M j, Y g:i A', strtotime($user->last_login))) : 'Never'; ?></td>
                        <td><?php echo esc_html(date('M j, Y', strtotime($user->created_at))); ?></td>
                        <td>
                            <?php if ($user->is_active): ?>
                                <a href="<?php echo wp_nonce_url(admin_url('admin.php?page=custom-auth-users&action=deactivate&user_id=' . $user->id), 'custom_auth_user_action'); ?>" style="color:orange;">Deactivate</a>
                            <?php else: ?>
                                <a href="<?php echo wp_nonce_url(admin_url('admin.php?page=custom-auth-users&action=activate&user_id=' . $user->id), 'custom_auth_user_action'); ?>" style="color:green;">Activate</a>
                            <?php endif; ?>
                            |
                            <a href="<?php echo wp_nonce_url(admin_url('admin.php?page=custom-auth-users&action=delete&user_id=' . $user->id), 'custom_auth_user_action'); ?>" style="color:red;" onclick="return confirm('Are you sure you want to delete this user?');">Delete</a>
                        </td>
                    </tr>
                    <?php endforeach; ?>
                    <?php endif; ?>
                </tbody>
            </table>

            <p><strong>Total Users:</strong> <?php echo count($users); ?></p>
        </div>
        <?php
    }

