// Initialize the plugin
function custom_user_authentication_init() {
    return Custom_User_Authentication::get_instance();
}

add_action('plugins_loaded', 'custom_user_authentication_init');

/**
 * Helper functions for theme developers
 */
function custom_auth_is_logged_in() {
    $auth = Custom_User_Authentication::get_instance();
    return $auth->is_custom_user_logged_in();
}

function custom_auth_get_current_user() {
    $auth = Custom_User_Authentication::get_instance();
    return $auth->get_current_custom_user();
}

function custom_auth_get_user($user_id) {
    $auth = Custom_User_Authentication::get_instance();
    return $auth->get_user_by_id($user_id);
}